package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVFormat.Predefined;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVFormatTest {

    @Test
    void testValueOf_withValidPredefinedFormat() {
        // Arrange
        String formatName = "DEFAULT";
        CSVFormat expectedFormat = CSVFormat.DEFAULT;

        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            CSVFormat.Predefined predefinedMock = Mockito.mock(CSVFormat.Predefined.class);
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf(formatName)).thenReturn(predefinedMock);
            Mockito.when(predefinedMock.getFormat()).thenReturn(expectedFormat);

            // Act
            CSVFormat actualFormat = CSVFormat.valueOf(formatName);

            // Assert
            assertSame(expectedFormat, actualFormat);
            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf(formatName));
            Mockito.verify(predefinedMock).getFormat();
        }
    }

    @Test
    void testValueOf_withInvalidFormat_throwsIllegalArgumentException() {
        String invalidFormatName = "NON_EXISTENT_FORMAT";

        try (MockedStatic<CSVFormat.Predefined> mockedPredefined = Mockito.mockStatic(CSVFormat.Predefined.class)) {
            mockedPredefined.when(() -> CSVFormat.Predefined.valueOf(invalidFormatName))
                    .thenThrow(IllegalArgumentException.class);

            assertThrows(IllegalArgumentException.class, () -> CSVFormat.valueOf(invalidFormatName));

            mockedPredefined.verify(() -> CSVFormat.Predefined.valueOf(invalidFormatName));
        }
    }

}
